package main

import "fmt"

func main() {
    // ---- Type assertion basics ----
    var i interface{} = 42

    // ---- Safe type assertion ----
    val, ok := i.(int)
    if ok {
        fmt.Printf("It's an int: %d\n", val)
    } else {
        fmt.Println("Not an int")
    }

    // ---- Unsafe type assertion (panics if wrong) ----
    // val := i.(string)  // Panic!

    // ---- Type assertion with different types ----
    var j interface{} = "Hello"

    // string
    str, ok := j.(string)
    if ok {
        fmt.Println("String:", str)
    }

    // bool (fails)
    _, ok = j.(bool)
    if ok {
        fmt.Println("It's a bool")
    } else {
        fmt.Println("Not a bool")
    }

    // ---- Type assertion on structs ----
    type Player struct {
        Name string
        Health int
    }

    var p interface{} = Player{Name: "Hero", Health: 100}

    player, ok := p.(Player)
    if ok {
        fmt.Printf("Player: %s (HP: %d)\n", player.Name, player.Health)
    }

    // ---- Type assertion with pointer ----
    var ptr interface{} = &Player{Name: "Aragorn", Health: 120}

    playerPtr, ok := ptr.(*Player)
    if ok {
        fmt.Printf("Pointer to Player: %s (HP: %d)\n", playerPtr.Name, playerPtr.Health)
    }

    // ---- Type assertion in functions ----
    printIfInt(42)
    printIfInt("Hello")
    printIfInt(3.14)

    // ---- Type assertion with maps ----
    data := map[string]interface{}{
        "name": "Hero",
        "health": 100,
        "items": []string{"Sword", "Shield"},
    }

    name, ok := data["name"].(string)
    if ok {
        fmt.Println("Name:", name)
    }

    health, ok := data["health"].(int)
    if ok {
        fmt.Println("Health:", health)
    }
}

func printIfInt(v interface{}) {
    if val, ok := v.(int); ok {
        fmt.Printf("It's an int: %d\n", val)
    } else {
        fmt.Printf("Not an int: %T\n", v)
    }
}

