func main() {
    var i interface{} = 42
    // Unsafe type assertion on wrong type
    val := i.(string)  // Panic!
    fmt.Println(val)
}

phase2.explanation:
Unsafe type assertion panics if the type doesn't match.

**The fix:**
```go
val, ok := i.(string)
if ok {
    fmt.Println(val)
} else {
    fmt.Println("Not a string")
}
```

**Go-chan says:**
"Use the safe version with `ok`. It won't panic."

phase3.solution:
package main

import "fmt"

func main() {
    data := map[string]interface{}{
        "name":   "Hero",
        "health": 100,
    }

    name, ok := data["name"].(string)
    if ok {
        fmt.Println("Name:", name)
    } else {
        fmt.Println("Name not found or not a string")
    }

    health, ok := data["health"].(int)
    if ok {
        fmt.Println("Health:", health)
    } else {
        fmt.Println("Health not found or not an int")
    }
}
